// Procesar los certificados recibidos
const certificates = $json.certificates || [];
const metadata = $json.metadata || {};

// Log de información
console.log(`Procesando ${certificates.length} certificados`);
console.log(`Enviado por: ${metadata.sent_by}`);

// Preparar salida para cada certificado
const items = certificates.map(cert => {
  return {
    json: {
      // Datos del estudiante
      studentName: cert.student_name,
      studentEmail: cert.student_email,

      // Datos del curso
      courseName: cert.course_name,
      courseCode: cert.course_code,

      // Datos del programa
      programName: cert.program_name,
      programCode: cert.program_code,

      // Datos académicos
      academicYear: cert.academic_year,
      semester: cert.semester,

      // Metadata
      issuedDate: new Date().toISOString(),
      issuedBy: metadata.sent_by,

      // Ejemplo: URL del certificado (puedes personalizarlo)
      certificateUrl: `https://certificados.example.com/${cert.course_code}/${cert.student_email}`,

      // Texto personalizado para el email
      emailSubject: `Certificado del curso ${cert.course_name}`,
      emailBody: `Estimado/a ${cert.student_name},\n\nNos complace informarle que ha completado exitosamente el curso ${cert.course_name} (${cert.course_code}) del programa ${cert.program_name}.\n\nSu certificado está disponible en el siguiente enlace.\n\nFelicitaciones por su logro.\n\nSaludos cordiales.`
    }
  };
});

return items;
